	 OWKEY
	,ICKEY
	,CTKEY
	,LOGGRPCD
	,CP
	,SLPRC
	,VOLTYPE
	,NEWYN
	,USDCP
	,USDSLPRC
	,WIDTHUNIT
	,LENGTHUNIT
	,HEIGHTUNIT
