	 #{owkey}
	,#{ickey}
	,#{ctkey}
	,#{loggrpcd}
	,#{cp}
	,#{slprc}
	,#{voltype}
	,#{newyn}
	,#{usdcp}
	,#{usdslprc}
	,#{widthunit}
	,#{lengthunit}
	,#{heightunit}
	,#{ackey}
	,#{ordstoptype}
	,#{nonibreason}
	,#{ordtype}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
)

mapper.update:
/* icom-master-icxct-sql-oracle.xml - updateTOrderMstIcxct */
UPDATE 	TADMIN_MST_ICXCT
    SET	 LOGGRPCD 		  	  	  = #{loggrpcd}
		,VOLTYPE 				  = #{voltype}
		,NEWYN 				  	  = #{newyn}
		,WIDTHUNIT 			  	  = #{widthunit}
		,LENGTHUNIT 			  = #{lengthunit}
		,HEIGHTUNIT 			  = #{heightunit}
		,ACKEY 				  	  = #{ackey}
		,OBPTKEY  				  = #{obptkey}
		,RNDKEY					  = #{rndkey}
		,ICGRKEY				  = #{icgrkey}
		,UPDATEDATE   		  	  = #{sysdate}
		,UPDATEURKEY  		  	  = #{surkey}
		,PKCTKEY                  = #{pkctkey}
		,CDOCKYN                  = #{cdockyn}
		,PKTYPE                   = #{pktype}
WHERE	OWKEY = #{owkey}
AND     ICKEY = #{ickey}
AND     CTKEY = #{ctkey}

